'use strict';

const {processOutgoingCookies} = require('../utils/outgoing-cookie-handler');

module.exports = function sessionCookieMiddleware(sessionCookieName) {
  return function (req, res, next) {
    if (!req.session || !req.internalUrl) {
      return next();
    }
    processOutgoingCookies(req, req.headers, sessionCookieName, next);
  };
};
